class Solution:
    def countOperations(self, num1: int, num2: int) -> int:
        ops = 0
        a, b = num1, num2
        while a and b:
            if a >= b:
                ops += a // b
                a %= b
            else:
                ops += b // a
                b %= a
        return ops

solutions.python:
class Solution:
    def countOperations(self, num1: int, num2: int) -> int:
        count = 0
        while num1 != 0 and num2 != 0:
            if num1 >= num2:
                num1 -= num2
            else:
                num2 -= num1
            count += 1
        return count

